import React, { useEffect, useRef } from 'react';
import PropTypes from 'prop-types';

const ProcessTimeline = ({ steps }) => {
  const containerRef = useRef(null);

  useEffect(() => {
    const container = containerRef.current;
    if (!container) return;

    const stepEls = container.querySelectorAll('.timeline-step');
    if (!stepEls.length) return;

    // Scroll-reveal observer
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            entry.target.classList.add('is-visible');
            observer.unobserve(entry.target);
          }
        });
      },
      { threshold: 0.15 }
    );
    stepEls.forEach((el) => observer.observe(el));

    // Measure icon centers using offsetTop (unaffected by CSS transforms)
    // so the line endpoints don't shift during the reveal animation.
    const updateLine = () => {
      const line = container.querySelector('.timeline-line');
      if (!line) return;

      const firstStep = stepEls[0];
      const lastStep = stepEls[stepEls.length - 1];
      const firstIcon = firstStep.querySelector('.timeline-icon');
      const lastIcon = lastStep.querySelector('.timeline-icon');
      if (!firstIcon || !lastIcon) return;

      const top =
        firstStep.offsetTop + firstIcon.offsetTop + firstIcon.offsetHeight / 2;
      const containerHeight = container.offsetHeight;
      const bottom =
        containerHeight -
        (lastStep.offsetTop + lastIcon.offsetTop + lastIcon.offsetHeight / 2);

      line.style.top = `${top}px`;
      line.style.bottom = `${bottom}px`;
    };

    updateLine();

    const resizeObserver = new ResizeObserver(updateLine);
    resizeObserver.observe(container);

    return () => {
      observer.disconnect();
      resizeObserver.disconnect();
    };
  }, []);

  let stepCounter = 0;

  return (
    <div className="process-timeline" ref={containerRef}>
      <div className="timeline-line"></div>
      {steps.map((step, index) => {
        const isStart = step.type === 'start';
        if (!isStart) stepCounter++;
        const displayNumber = isStart ? null : String(stepCounter);

        return (
          <div
            key={index}
            className={`timeline-step ${step.type || 'step'}`}
            style={{ transitionDelay: `${index * 0.1}s` }}
          >
            <div
              className={`timeline-icon ${
                step.type === 'cycle' ? 'is-cycle' : ''
              }`}
            >
              <span className={`icon solid ${step.icon}`}></span>
              {displayNumber && (
                <span className="step-number">{displayNumber}</span>
              )}
            </div>
            <div className="timeline-content">
              <h3>{step.title}</h3>
              {step.text && <p>{step.text}</p>}
            </div>
          </div>
        );
      })}
    </div>
  );
};

ProcessTimeline.propTypes = {
  steps: PropTypes.arrayOf(
    PropTypes.shape({
      icon: PropTypes.string.isRequired,
      title: PropTypes.string.isRequired,
      text: PropTypes.string,
      type: PropTypes.string,
    })
  ).isRequired,
};

export default ProcessTimeline;
