import React, { useState } from 'react';
import { projects, categories } from '../data/projects';

const ProjectsSection = () => {
  const [activeCategory, setActiveCategory] = useState('Alle');

  const filteredProjects =
    activeCategory === 'Alle'
      ? projects
      : projects.filter((p) => p.category === activeCategory);

  return (
    <section className="wrapper style5 special">
      <div className="inner">
        <header className="major">
          <h2>Referenzprojekte</h2>
          <p>Ein Auszug aus Projekten, die wir erfolgreich umgesetzt haben.</p>
        </header>

        <div className="project-filters">
          {categories.map((cat) => (
            <button
              key={cat.id}
              className={activeCategory === cat.name ? 'active' : ''}
              onClick={() => setActiveCategory(cat.name)}
            >
              {cat.name}
            </button>
          ))}
        </div>

        <div className="project-grid">
          {filteredProjects.map((project, idx) => (
            <div
              key={idx}
              className={`project-card-wrapper ${
                project.featured ? 'featured' : ''
              } ${project.categoryId || ''}`}
            >
              <div className="project-card">
                <div className="project-image">
                  <img src={project.image} alt={project.title} />
                  <div className="category-label">{project.category}</div>
                </div>
                <div className="project-content">
                  <h3>{project.title}</h3>
                  <div className="description">
                    {Array.isArray(project.description) ? (
                      project.description.map((p, pIdx) => (
                        <p key={pIdx}>{p}</p>
                      ))
                    ) : (
                      <p>{project.description}</p>
                    )}
                  </div>

                  {project.features && (
                    <ul className="features-list">
                      {project.features.map((feat, fIdx) => (
                        <li key={fIdx}>{feat}</li>
                      ))}
                    </ul>
                  )}

                  <div className="technologies">
                    {project.technologies.map((tech, tIdx) => (
                      <span key={tIdx} className="tech-badge">
                        {tech}
                      </span>
                    ))}
                  </div>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
};

export default ProjectsSection;
